mapper.select:
SELECT FROM orders o INNER JOIN `user` u ON u.id = o.user_id
AND o.status = #{status}
ORDER BY o.id DESC

mapper.update:
UPDATE orders
SET status = #{toStatus}
WHERE id = #{id}
  AND status = #{fromStatus}

UPDATE orders
SET status = 1,
    tracking_no = #{trackingNo}
WHERE id = #{id}
  AND status = 0

mapper.select:
SELECT COUNT(1)
FROM orders
WHERE status = #{status}
